   229	func (h *calicoIPPoolHandler) platformIsROKS(ctx context.Context) (bool, error) {
   230		// Submariner GW is deployed on ROKS using LB service with specific annotations.
   231		serviceUnstructured, err := h.dynClient.
   232			Resource(corev1.SchemeGroupVersion.WithResource("services")).
   233			Namespace(h.namespace).
   234			Get(ctx, GwLBSvcName, metav1.GetOptions{})
   235		if apierrors.IsNotFound(err) {
