		Hook:     packetfilter.ChainHookInput,
		Priority: packetfilter.ChainPriorityLast,
		JumpRule: &packetfilter.Rule{
			Proto:       packetfilter.RuleProtoUDP,
			Action:      packetfilter.RuleActionJump,
