	t := newTestDriver()

	Context("to gateway node", func() {
		It("should stop the pinger", func() {
			_ = t.CreateEndpoint(t.newSubmEndpoint(healthCheckIP1))
			t.pingerMap[healthCheckIP1].AwaitStart()

			_ = t.CreateLocalHostEndpoint()
